SELECT COUNT(PB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB PB ON PB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(S.SIGLA_CAMPUS) = LOWER('jat') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%artes%' AND PB.ANO GLOB '[0-9][0-9][0-9][0-9]' AND CAST(PB.ANO AS INTEGER) = 2022 AND LOWER(COALESCE(PB.TIPO, '')) = 'capitulo de livro'